#include <QProcess>
#include <QTimer>
#include <QThread>

class AgenticExecutor : public QObject {
    Q_OBJECT
public:
    void executeCommand(const QString& cmd) {
        QProcess* process = new QProcess(this);
        connect(process, &QProcess::finished, this, &AgenticExecutor::onFinished);
        process->start(cmd);
    }
};

// AFTER (Win32): src/agentic_executor_win32.cpp
#include "RawrXD_Executor.dll"

#pragma comment(lib, "RawrXD_Executor.lib")

class AgenticExecutor_Win32 {
public:
    void executeCommand(const std::wstring& cmd) {
        RawrXD::ToolExecutionEngine engine;
        
        // Use callback instead of signal/slot
        engine.SetCallback([this](const RawrXD::ProcessResult& result) {
            onFinished(result);
        });
        
        engine.Execute(cmd, {});
    }
    
private:
    void onFinished(const RawrXD::ProcessResult& result) {
        // Handle completion
    }
};

