# Verify-QtRemoval.ps1
# Run this after each migration batch

Write-Host "`n🔍 QT REMOVAL VERIFICATION" -ForegroundColor Cyan

$srcPath = "D:\RawrXD\src"

# Check 1: No Qt includes remain
$qtIncludes = Get-ChildItem -Path $srcPath -Recurse -Include *.cpp, *.hpp, *.h | 
    Select-String "#include\s*[<\"](Qt|Q)[a-zA-Z]+" | 
    Select-Object -ExpandProperty Line -Unique

if ($qtIncludes) {
