    Write-Host "❌ FAIL: $($qobjects.Count) Q_OBJECT macros still present" -ForegroundColor Red
} else {
    Write-Host "✅ PASS: No Q_OBJECT macros found" -ForegroundColor Green
}

# Check 3: Binaries don't depend on Qt
