    $deps = dumpbin /dependents $binPath 2>$null
    $qtDeps = $deps | Select-String "Qt5|Qt6|qt"
    
    if ($qtDeps) {
        Write-Host "❌ FAIL: Binary still depends on Qt:" -ForegroundColor Red
        $qtDeps | ForEach-Object { Write-Host "   $_" -ForegroundColor DarkRed }
